const images = $input.all().reduce((acc, item, index) => {
  acc[`data${index}`] = item.binary.data;
  return acc;
}, {});
return [{ json: {}, binary: images }]

const input = $input.all();
const totalCount = input.length;
const totals = {}
const monthsWise = {};
const statusOnWhole = {};
const srTypes = {};
const srPriorities = {};
const hcEndUserKeys = new Set();
const statusKeys = new Set();
const monthKeys = new Set();

for (let i = 0; i < totalCount; i++) {
  const record = input[i].json;
  const cre = record.Cre;
  const status = record.Status;
  const type = record.Type || "NoType";
  const priority = record.Priority.length > 3 ? record.Priority : "No Priority";

  statusKeys.add(status);
  hcEndUserKeys.add(record["HC/End User"]);
  monthKeys.add(cre);

  if (cre) {
    monthsWise[cre] || (monthsWise[cre] = {});
    totals[cre] = (totals[cre] || 0) + 1;
    monthsWise[cre][record["HC/End User"]] =
      (monthsWise[cre][record["HC/End User"]] || 0) + 1;
    monthsWise[cre][status] = (monthsWise[cre][status] || 0) + 1;
  }
  if (status) {
    statusOnWhole[status] = (statusOnWhole[status] || 0) + 1;
  }
  if (type) {
    srTypes[type] = (srTypes[type] || 0) + 1;
  }
  if (priority) {
    srPriorities[priority] = (srPriorities[priority] || 0) + 1;
  }
}

return [
  { totalCount, totals, monthsWise, statusOnWhole, srTypes, srPriorities },
  {
    monthKeys: [...monthKeys],
    hcEndUserKeys: [...hcEndUserKeys],
    statusKeys: [...statusKeys],
  },
];

const input = $input.all();
const data = input[0].json;
const meta = input[1].json;
const hceKeys = meta["hcEndUserKeys"] || [];
const monthKeys = meta["monthKeys"] || [];
const statusKeys = meta["statusKeys"] || [];

function chart(type, labels, dataKeys, dataSource, title, stacked) {
  let dataSets = [];
  let options = {};
  if (type === "bar" || type === "line") {
    dataSets = dataKeys.map((dkey) => {
      const dataArr = labels.map((lkey) => {
        return dataSource[lkey][dkey];
      });
      return {
        label: dkey?.trim(),
        data: dataArr,
      };
    });
    options = {
      title: { display: true, text: title },
      legend: {
        display: true,
        position: "right",
        labels: {
          fontStyle: "bold",
          fontSize: 10,
          boxWidth: 12,
        },
      },
      scales: {
        xAxes: [
          {
            gridLines: {
              display: false,
              drawBorder: false,
            },
            stacked: stacked,
            categoryPercentage: 0.5,
            barPercentage: 1,
          },
        ],
        yAxes: [
          {
            gridLines: {
              drawBorder: false,
            },
            stacked: stacked,
            ticks: { beginAtZero: true },
          },
        ],
      },
      plugins: {
        datalabels: {
          display: true,
          color: stacked === true ? "#000" : "#000",
          anchor: stacked === true ? "center" : "end",
          align: stacked === true ? "center" : "top",
          font: {
            weight: "bold",
            size: 11,
          },
        },
      },
    };
  }
  if (type === "pie") {
    const d = Object.fromEntries(
      Object.entries(dataSource).sort((a, b) => b[1] - a[1]),
    );
    labels = Object.keys(d);
    dataSets = [
      {
        borderWidth: 1,
        borderColor: "#fff",
        data: Object.values(d),
      },
    ];
    options = {
      title: { display: true, text: title },
      legend: {
        display: true,
        position: "right",
        labels: {
          fontStyle: "bold",
          fontSize: 10,
          boxWidth: 12,
        },
      },
      plugins: {
        datalabels: {
          display: true,
          color: "#000",
          anchor: "center",
          align: "center",
          font: {
            weight: "bold",
            size: 11,
          },
        },
      },
    };
  }
  const config = {
    type: type,
    data: {
      labels: labels,
      datasets: dataSets,
    },
    options: options,
    plugins: [],
  };

  return {
    backgroundColor: "#fff",
    width: 500,
    height: 300,
    devicePixelRatio: 1.0,
    chart: config,
  };
}
const bar1 = chart(
  "bar",
  monthKeys,
  hceKeys,
  data.monthsWise,
  "Service Interation Raised By HC vs End User",
  false,
);
const bar2 = chart(
  "bar",
  monthKeys,
  statusKeys,
  data.monthsWise,
  "Service Interction Summary Bases on Status",
  true,
);
const pie1 = chart(
  "pie",
  null,
  null,
  data.srPriorities,
  "Service Request by Priority",
  false,
);
const pie2 = chart(
  "pie",
  null,
  null,
  data.totals,
  "Service Requests Monthly",
  false,
);
return [bar1, bar2, pie1, pie2];

const binaries = $input.item.binary;

const chartsB64 = [
  binaries.data0 ? `data:${binaries.data0.mimeType};base64,${binaries.data0.data}` : null,
  binaries.data1 ? `data:${binaries.data1.mimeType};base64,${binaries.data1.data}` : null,
  binaries.data2 ? `data:${binaries.data2.mimeType};base64,${binaries.data2.data}` : null,
  binaries.data3 ? `data:${binaries.data3.mimeType};base64,${binaries.data3.data}` : null
].filter(Boolean);

const chartLabels = [
  "Resource Allocation (HC vs End User)",
  "Ticket Status Distribution Summary",
  "Service Request Priority Tracking",
  "Service Request Category Types Volumetrics"
];

const gridItemsHtml = chartsB64.map((b64Url, index) => `
  <div class="card">
    <div class="card-header">${chartLabels[index]}</div>
    <img src="${b64Url}" />
  </div>
`).join('');

const htmlDashboard = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body {
      font-family: 'Helvetica Neue', Arial, sans-serif;
      background-color: #f8f9fa;
      margin: 0;
      padding: 35px;
      width: 1100px; /* Locked width canvas for 2-column rendering */
      box-sizing: border-box;
    }
    .header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 2px solid #e9ecef;
      padding-bottom: 15px;
      margin-bottom: 30px;
    }
    .title {
      font-size: 26px;
      font-weight: 800;
      color: #1e293b;
      letter-spacing: -0.5px;
    }
    .meta-date {
      font-size: 13px;
      color: #64748b;
      font-weight: 500;
      background: #edf2f7;
      padding: 6px 12px;
      border-radius: 20px;
    }
    .dashboard-grid {
      display: grid;
      grid-template-columns: repeat(2, 1fr); /* Forces exactly 2 charts per row */
      gap: 25px; /* Margin space between individual cards */
    }
    .card {
      background-color: #ffffff;
      border-radius: 12px;
      box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.05), 0 4px 6px -4px rgba(0, 0, 0, 0.05);
      border: 1px solid #e2e8f0;
      padding: 20px;
      display: flex;
      flex-direction: column;
      align-items: center;
    }
    .card-header {
      font-size: 12px;
      font-weight: 700;
      color: #475569;
      text-transform: uppercase;
      letter-spacing: 0.5px;
      margin-bottom: 15px;
      align-self: flex-start;
      border-left: 3px solid #3b82f6;
      padding-left: 8px;
    }
    .card img {
      width: 100%;
      max-width: 480px;
      height: auto;
      display: block;
    }
  </style>
</head>
<body>
  <div class="header">
    <div class="title">Operations Performance Dashboard</div>
    <div class="meta-date">Generated: ${new Date().toLocaleDateString('en-IN', { year: 'numeric', month: 'short', day: 'numeric' })}</div>
  </div>
  <div class="dashboard-grid">
    ${gridItemsHtml}
  </div>
</body>
</html>
`;

return [{ json: { dashboardHtml: htmlDashboard } }];
